from typing import Callable, List, Generic, TypeVar, Tuple

# Type variable for Segment Tree's data type
T = TypeVar('T')

class StringHasher:
    """
    A utility class for efficient O(1) substring hash calculation using polynomial rolling hash.
    It employs double hashing (two different bases and moduli) to minimize collision probability.
    This is highly useful for string matching, finding palindromes, or solving problems
    that require quick comparison of substrings.
    """
    # Use fixed, large prime moduli and bases for consistency and good distribution.
    # It's common practice in competitive programming to use these or similar fixed values
    # rather than random ones to ensure deterministic behavior across runs.
    _BASES = (31, 37)  # Two distinct small prime bases
    _MODULI = (1_000_000_007, 1_000_000_009) # Two distinct large prime moduli

    def __init__(self, s: str):
        """
        Initializes the StringHasher for a given string.
        Precomputes prefix hashes and powers of bases in O(N) time.

        Args:
            s: The input string for which to compute hashes.
        """
        self.n = len(s)
        # _prefix_hashes[i][j] stores the hash of s[0...j-1] for the i-th hash function.
        self._prefix_hashes: List[List[int]] = [[0] * (self.n + 1) for _ in range(2)]
        # _powers[i][j] stores (base_i)^j % modulus_i.
        self._powers: List[List[int]] = [[1] * (self.n + 1) for _ in range(2)]

        for i in range(2):
            base = StringHasher._BASES[i]
            mod = StringHasher._MODULI[i]
            
            for j in range(self.n):
                # Calculate prefix hash: H(s[0...j]) = (H(s[0...j-1]) * base + ord(s[j])) % mod
                self._prefix_hashes[i][j+1] = (self._prefix_hashes[i][j] * base + ord(s[j])) % mod
                # Calculate powers of base: base^j = (base^(j-1) * base) % mod
                self._powers[i][j+1] = (self._powers[i][j] * base) % mod

    def get_hash(self, left: int, right: int) -> Tuple[int, int]:
        """
        Calculates the rolling hash of the substring s[left:right+1] (inclusive indices).
        Returns a tuple of two hashes (for double hashing) in O(1) time.

        The hash of a substring s[left...right] is computed using the formula:
        H(s[left...right]) = (prefix_hash[right+1] - prefix_hash[left] * powers[length]) % mod
        where length = right - left + 1.

        Args:
            left: The 0-based starting index of the substring.
            right: The 0-based ending index of the substring (inclusive).

        Returns:
            A tuple (hash1, hash2) representing the double hash of the substring.

        Raises:
            ValueError: If left or right indices are out of bounds or left > right.
        """
        if not (0 <= left <= right < self.n):
            raise ValueError(f"Invalid indices: left={left}, right={right} for string of length {self.n}")

        hash_values = []
        substring_length = right - left + 1

        for i in range(2):
            mod = StringHasher._MODULI[i]
            
            # Calculate the hash using prefix hashes and powers.
            # (A - B % M + M) % M is used to correctly handle negative results from subtraction.
            h = (self._prefix_hashes[i][right+1] - \
                 (self._prefix_hashes[i][left] * self._powers[i][substring_length]) % mod + mod) % mod
            hash_values.append(h)
            
        return tuple(hash_values)

