class SegmentTree(Generic[T]):
    """
    A generic Segment Tree implementation for efficient range queries and point updates.
    It supports any associative aggregation function (e.g., sum, min, max, GCD).
    This data structure is fundamental for problems involving array range queries,
    dynamic programming optimizations, and certain graph algorithms.
    """
    def __init__(self, data: List[T], func: Callable[[T, T], T], default_value: T):
        """
        Initializes the Segment Tree.
        Time complexity: O(N) to build the tree.

        Args:
            data: The initial list of values. The tree will be built over this data.
            func: An associative function (e.g., operator.add, min, max, operator.gcd)
                  used for aggregation. It must satisfy func(a, func(b, c)) == func(func(a, b), c).
            default_value: The identity element for the 'func'.
                           E.g., 0 for sum, float('inf') for min, float('-inf') for max, 0 for GCD.
        """
        self.n = len(data)
        self.func = func
        self.default_value = default_value
        # The tree array uses 1-based indexing conceptually, with leaves at indices n to 2n-1.
        # This allows for simpler parent/child calculations (parent of i is i//2, children are 2i, 2i+1).
        # We allocate 2*n space to accommodate this structure.
        self.tree: List[T] = [default_value] * (2 * self.n)

        if self.n == 0:
            return

        # Initialize leaves of the tree with the input data.
        # The actual data elements are stored starting from index `self.n`.
        for i in range(self.n):
            self.tree[self.n + i] = data[i]

        # Build the rest of the tree by aggregating up from the leaves.
        # Nodes at index `i` store the aggregation of their children `2*i` and `2*i+1`.
        for i in range(self.n - 1, 0, -1):
            self.tree[i] = self.func(self.tree[2 * i], self.tree[2 * i + 1])

    def update(self, index: int, value: T) -> None:
        """
        Updates the value at a specific index in the original data array.
        Then, it updates all ancestors of that index in the tree.
        Time complexity: O(log N).

        Args:
            index: The 0-based index of the element to update.
            value: The new value for the element.

        Raises:
            IndexError: If the index is out of bounds.
        """
        if not (0 <= index < self.n):
            raise IndexError(f"Index {index} out of bounds for data of length {self.n}")

        # Map the 0-based data index to the 1-based tree array index for leaves.
        pos = self.n + index
        self.tree[pos] = value
        
        # Traverse up to the root, updating each parent node.
        # `pos // 2` gives the parent. `pos ^ 1` gives the sibling node (if pos is left child, pos+1; if right, pos-1).
        while pos > 1:
            self.tree[pos // 2] = self.func(self.tree[pos], self.tree[pos ^ 1])
            pos //= 2

    def query(self, left: int, right: int) -> T:
        """
        Queries the aggregated value for a given range [left, right) (exclusive of right).
        This means the query includes `left` but excludes `right`.
        Time complexity: O(log N).

        Args:
            left: The 0-based starting index of the range (inclusive).
            right: The 0-based ending index of the range (exclusive).

        Returns:
            The aggregated value for the specified range.
            Returns `default_value` if the range is empty (left == right).

        Raises:
            ValueError: If left or right indices are out of bounds or left > right.
        """
        if not (0 <= left <= right <= self.n):
            raise ValueError(f"Invalid range: left={left}, right={right} for data of length {self.n}")
        if left == right:
            return self.default_value # Empty range

        res = self.default_value
        # Map 0-based query indices to 1-based tree array indices for leaves.
        left += self.n
        right += self.n

        # Traverse the tree to find the required segments.
        # The loop stops when 'left' and 'right' pointers meet.
        while left < right:
            # If 'left' is a right child, it means its parent does not fully cover the range
            # from 'left' upwards. So, include 'left' itself and move to its sibling's parent.
            if left % 2 == 1:
                res = self.func(res, self.tree[left])
                left += 1
            # If 'right' is a right child, it means it's the rightmost node in a covered segment.
            # Include 'right-1' (its sibling, which is a left child) and move to its parent.
            if right % 2 == 1:
                right -= 1
                res = self.func(res, self.tree[right])
            
            # Move up to the parent level.
            left //= 2
            right //= 2
        return res

